optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT ?cpd ?drug ?drugDesc ?equation ?reaction
WHERE {

  SERVICE <http://localhost:8892/sparql/> {
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/description> ?drugDesc . # ?drug:drugs, ?drugDesc:Literal
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/drugCategory> <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugcategory/cathartics> .
    ?drug <http://www4.wiwiss.fu-berlin.de/drugbank/resource/drugbank/keggCompoundId> ?cpd .
  }

  SERVICE <http://localhost:8895/sparql/> {
    ?reaction <http://bio2rdf.org/ns/kegg#xEnzyme> ?enzyme . # ?reaction:Reaction, ?enzyme:Enzyme
    ?reaction <http://bio2rdf.org/ns/kegg#equation> ?equation . # ?reaction:Reaction, ?equation:Literal
    ?enzyme <http://bio2rdf.org/ns/kegg#xSubstrate> ?cpd . # ?enzyme:Enzyme, ?cpd:Compound
    ?enzyme <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://bio2rdf.org/ns/kegg#Enzyme> .
  }
}
LIMIT 1000
